import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppTab {
  MAP = 'MAP',
  STUDIO = 'STUDIO',
  HISTORY = 'HISTORY'
}

export enum ImageSize {
  K1 = '1K',
  K2 = '2K',
  K4 = '4K'
}

export interface RouteMarker {
  km: number;
  name: string;
  lat: number;
  lng: number;
  description: string;
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  timestamp: number;
  model: string;
}

import { RouteMarker } from './types';

export const BDM_ROUTE: RouteMarker[] = [
  { km: 0, name: 'Death March Marker (Zero KM)', lat: 14.4331, lng: 120.4851, description: 'The official starting point in Mariveles, Bataan.' },
  { km: 10, name: 'Cabcaben', lat: 14.4442, lng: 120.5397, description: 'Entering the coastal road of Limay.' },
  { km: 31, name: 'Orion Marker', lat: 14.6186, lng: 120.5819, description: 'Past the Limay municipal hall, heading towards Orion.' },
  { km: 45, name: 'Pilar / Balanga', lat: 14.6811, lng: 120.5422, description: 'Crossing the historic Pilar-Balanga boundary.' },
  { km: 58, name: 'Abucay Church', lat: 14.7214, lng: 120.5392, description: 'A significant landmark near the halfway point.' },
  { km: 70, name: 'Hermosa', lat: 14.8317, lng: 120.5050, description: 'Leaving Bataan and approaching the Pampanga border.' },
  { km: 83, name: 'Lubao', lat: 14.9213, lng: 120.5989, description: 'The long stretch of Jose Abad Santos Avenue.' },
  { km: 92, name: 'Guagua', lat: 14.9658, lng: 120.6289, description: 'Almost there. The fatigue is real.' },
  { km: 102, name: 'Old San Fernando Train Station', lat: 15.0306, lng: 120.6942, description: 'The Finish Line. A place of deep historical significance.' }
];

export const MODEL_FLASH = 'gemini-2.5-flash-image';
export const MODEL_PRO = 'gemini-3-pro-image-preview';

export const SYSTEM_PROMPTS = {
  editor: `You are an expert AI image editor. Your goal is to modify the provided image based on the user's instructions while maintaining high quality and consistency. If asked for filters, apply them subtly. If asked to remove objects, blend the background seamlessly.`
};

import { GoogleGenAI, Type } from "@google/genai";
import { ImageSize } from "../types";
import { MODEL_FLASH, MODEL_PRO } from "../constants";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async generateImage(prompt: string, size: ImageSize): Promise<string> {
    const response = await this.ai.models.generateContent({
      model: MODEL_PRO,
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: size
        },
        tools: [{ googleSearch: {} }] // Only available on Pro
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image data returned from API");
  }

  async editImage(base64Image: string, prompt: string, mimeType: string = 'image/png'): Promise<string> {
    // Strip header if present
    const cleanBase64 = base64Image.replace(/^data:image\/\w+;base64,/, '');

    const response = await this.ai.models.generateContent({
      model: MODEL_FLASH,
      contents: {
        parts: [
          {
            inlineData: {
              data: cleanBase64,
              mimeType: mimeType,
            },
          },
          {
            text: prompt,
          },
        ],
      },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No edited image data returned from API");
  }
}

import React, { useState, useEffect } from 'react';
import { AppTab } from './types';
import MapDisplay from './components/MapDisplay';
import ImageStudio from './components/ImageStudio';
import ApiKeyGuard from './components/ApiKeyGuard';
import { Map, Image as ImageIcon, History, ShieldCheck } from 'lucide-react';

