import React, { useState } from 'react';
import { BDM_ROUTE } from '../constants';
import { RouteMarker } from '../types';
import { Info, Navigation, Trophy, Ruler } from 'lucide-react';

const MapDisplay: React.FC = () => {
  const [selectedMarker, setSelectedMarker] = useState<RouteMarker | null>(BDM_ROUTE[0]);

  // To simulate an "offline" map, we'll create a custom SVG visualization of the route
  // The route starts at Mariveles and ends at San Fernando.
  // Normalize coordinates for the SVG box
  const minLat = Math.min(...BDM_ROUTE.map(m => m.lat));
  const maxLat = Math.max(...BDM_ROUTE.map(m => m.lat));
  const minLng = Math.min(...BDM_ROUTE.map(m => m.lng));
  const maxLng = Math.max(...BDM_ROUTE.map(m => m.lng));

  const padding = 50;
  const width = 400;
  const height = 600;

  const project = (lat: number, lng: number) => {
    const x = padding + ((lng - minLng) / (maxLng - minLng)) * (width - 2 * padding);
    const y = (height - padding) - ((lat - minLat) / (maxLat - minLat)) * (height - 2 * padding);
    return { x, y };
  };

  const pathData = BDM_ROUTE.reduce((acc, marker, i) => {
    const { x, y } = project(marker.lat, marker.lng);
    return i === 0 ? `M ${x} ${y}` : `${acc} L ${x} ${y}`;
  }, "");

  return (
    <div className="animate-in fade-in duration-500">
      <div className="bg-slate-900 border-b border-slate-800 p-4 sticky top-[53px] z-40">
        <div className="flex items-center gap-4 overflow-x-auto pb-2 no-scrollbar">
          <div className="flex-shrink-0 flex items-center gap-2 bg-slate-800/50 px-3 py-1.5 rounded-lg border border-slate-700">
            <Ruler className="w-4 h-4 text-red-500" />
            <span className="text-sm font-bold">102 KM</span>
          </div>
          <div className="flex-shrink-0 flex items-center gap-2 bg-slate-800/50 px-3 py-1.5 rounded-lg border border-slate-700">
            <Trophy className="w-4 h-4 text-yellow-500" />
            <span className="text-sm font-bold">18:00 CUTOFF</span>
          </div>
          <div className="flex-shrink-0 flex items-center gap-2 bg-green-500/10 px-3 py-1.5 rounded-lg border border-green-500/30">
            <Navigation className="w-4 h-4 text-green-500" />
            <span className="text-sm font-bold text-green-500">LIVE TRACK</span>
          </div>
        </div>
      </div>

      <div className="p-4 flex flex-col items-center">
        <div className="relative w-full max-w-lg aspect-[2/3] bg-slate-900/40 rounded-3xl border border-slate-800 shadow-2xl overflow-hidden mb-6">
          {/* Map Grid Pattern */}
          <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle, #fff 1px, transparent 1px)', backgroundSize: '24px 24px' }} />

          <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-full p-4 drop-shadow-lg">
            {/* Route Path */}
            <path 
              d={pathData} 
              fill="none" 
              stroke="white" 
              strokeWidth="2" 
              strokeOpacity="0.1"
              strokeDasharray="4 4"
            />
            <path 
              d={pathData} 
              fill="none" 
              stroke="red" 
              strokeWidth="4" 
              strokeLinecap="round"
              strokeLinejoin="round"
              className="drop-shadow-[0_0_8px_rgba(239,68,68,0.5)]"
            />

            {/* Markers */}
            {BDM_ROUTE.map((marker, idx) => {
              const { x, y } = project(marker.lat, marker.lng);
              const isSelected = selectedMarker?.km === marker.km;
              return (
                <g 
                  key={marker.km} 
                  onClick={() => setSelectedMarker(marker)}
                  className="cursor-pointer group"
                >
                  <circle 
                    cx={x} cy={y} 
                    r={isSelected ? "8" : "5"} 
                    fill={isSelected ? "#ef4444" : "#1e293b"} 
                    stroke={isSelected ? "white" : "#475569"} 
                    strokeWidth="2"
                    className="transition-all duration-300"
                  />
                  {isSelected && (
                    <circle cx={x} cy={y} r="12" fill="none" stroke="#ef4444" strokeWidth="2" className="animate-ping" />
                  )}
                  {/* KM Labels for key points */}
                  {(idx % 2 === 0 || idx === BDM_ROUTE.length - 1) && (
                    <text 
                      x={x + 10} 
                      y={y + 5} 
                      fill="white" 
                      fontSize="10" 
                      fontWeight="bold" 
                      className="opacity-40 group-hover:opacity-100 pointer-events-none"
                    >
                      KM {marker.km}
                    </text>
                  )}
                </g>
              );
            })}
          </svg>

          {/* Map Controls */}
          <div className="absolute top-4 right-4 flex flex-col gap-2">
            <button className="bg-slate-800/80 p-2 rounded-lg border border-slate-700 backdrop-blur-sm"><Info className="w-4 h-4" /></button>
          </div>
        </div>

        {/* Selected Marker Detail Card */}
        {selectedMarker && (
          <div className="w-full max-w-lg bg-slate-900 rounded-2xl border border-slate-800 p-5 animate-in slide-in-from-bottom-4">
            <div className="flex justify-between items-start mb-4">
              <div>
                <span className="text-red-500 font-bold text-xs uppercase tracking-tighter">Checkpoint KM {selectedMarker.km}</span>
                <h3 className="text-xl font-bold text-white mt-1">{selectedMarker.name}</h3>
              </div>
              <div className="bg-red-500/10 px-3 py-1 rounded-full border border-red-500/20">
                <span className="text-xs font-bold text-red-500">{selectedMarker.km === 0 ? 'START' : selectedMarker.km === 102 ? 'FINISH' : 'ACTIVE'}</span>
              </div>
            </div>
            <p className="text-slate-400 text-sm leading-relaxed">
              {selectedMarker.description}
            </p>
            <div className="grid grid-cols-2 gap-4 mt-6">
              <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
                <span className="block text-[10px] text-slate-500 font-bold uppercase mb-1">Elevation</span>
                <span className="text-sm font-semibold">12m ASL</span>
              </div>
              <div className="bg-slate-800/50 p-3 rounded-xl border border-slate-700/50">
                <span className="block text-[10px] text-slate-500 font-bold uppercase mb-1">Pace Goal</span>
                <span className="text-sm font-semibold">7:30 min/km</span>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default MapDisplay;

import React, { useState, useRef } from 'react';
import { GeminiService } from '../services/geminiService';
import { ImageSize } from '../types';
import { Wand2, ImagePlus, Loader2, Download, Eraser, Sparkles, SlidersHorizontal, ArrowRight } from 'lucide-react';

const ImageStudio: React.FC = () => {
  const [mode, setMode] = useState<'generate' | 'edit'>('generate');
  const [prompt, setPrompt] = useState('');
  const [size, setSize] = useState<ImageSize>(ImageSize.K1);
  const [isProcessing, setIsProcessing] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [editSource, setEditSource] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAction = async () => {
    if (!prompt.trim()) return;
    setIsProcessing(true);
    const gemini = new GeminiService();

    try {
      if (mode === 'generate') {
        const url = await gemini.generateImage(prompt, size);
        setResultImage(url);
      } else {
        if (!editSource) {
          alert("Please upload an image to edit first.");
          return;
        }
        const url = await gemini.editImage(editSource, prompt);
        setResultImage(url);
      }
    } catch (error) {
      console.error(error);
      alert("Operation failed. Please check your API configuration and try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setEditSource(ev.target?.result as string);
        setResultImage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="p-4 max-w-2xl mx-auto space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      {/* Mode Switcher */}
      <div className="flex p-1 bg-slate-900 border border-slate-800 rounded-2xl">
        <button 
          onClick={() => { setMode('generate'); setPrompt(''); }}
          className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${mode === 'generate' ? 'bg-slate-800 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
        >
          <Sparkles className="w-4 h-4" />
          Generate
        </button>
        <button 
          onClick={() => { setMode('edit'); setPrompt(''); }}
          className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-sm font-bold transition-all ${mode === 'edit' ? 'bg-slate-800 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
        >
          <Wand2 className="w-4 h-4" />
          Edit Photo
        </button>
      </div>

      {/* Editor/Input Area */}
      <div className="bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden">
        <div className="p-5 border-b border-slate-800 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse"></div>
            <h2 className="text-sm font-bold text-white uppercase tracking-wider">{mode === 'generate' ? 'Creation Lab' : 'Magic Editor'}</h2>
          </div>
          {mode === 'generate' && (
            <select 
              value={size} 
              onChange={(e) => setSize(e.target.value as ImageSize)}
              className="bg-slate-800 border border-slate-700 text-xs font-bold px-2 py-1 rounded-lg text-slate-300 focus:outline-none focus:ring-1 focus:ring-blue-500"
            >
              <option value={ImageSize.K1}>1K Standard</option>
              <option value={ImageSize.K2}>2K High-Res</option>
              <option value={ImageSize.K4}>4K Ultra</option>
            </select>
          )}
        </div>

        <div className="p-5 space-y-4">
          {mode === 'edit' && (
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="group relative border-2 border-dashed border-slate-800 rounded-2xl aspect-video flex flex-col items-center justify-center cursor-pointer hover:border-slate-700 transition-colors bg-slate-800/20"
            >
              {editSource ? (
                <img src={editSource} className="w-full h-full object-cover rounded-xl" alt="Source" />
              ) : (
                <>
                  <ImagePlus className="w-10 h-10 text-slate-600 group-hover:text-slate-400 mb-3 transition-colors" />
                  <p className="text-sm text-slate-500 font-medium">Select a photo from your trek</p>
                </>
              )}
              <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" />
            </div>
          )}

          <div className="relative">
            <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder={mode === 'generate' ? "A heroic ultramarathon runner crossing the finish line at sunrise in a cinematic style..." : "Add a retro filter and make the sky more dramatic..."}
              className="w-full bg-slate-800/50 border border-slate-700 rounded-2xl p-4 text-sm text-slate-100 placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-blue-500/50 min-h-[120px] resize-none"
            />
            <button
              onClick={handleAction}
              disabled={isProcessing || !prompt.trim() || (mode === 'edit' && !editSource)}
              className="absolute bottom-4 right-4 bg-white text-slate-950 px-4 py-2 rounded-xl font-bold text-xs flex items-center gap-2 hover:bg-slate-200 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg"
            >
              {isProcessing ? <Loader2 className="w-4 h-4 animate-spin" /> : mode === 'generate' ? <Sparkles className="w-4 h-4" /> : <ArrowRight className="w-4 h-4" />}
              {isProcessing ? 'Thinking...' : mode === 'generate' ? 'Generate' : 'Apply'}
            </button>
          </div>
        </div>
      </div>

      {/* Result Display */}
      {resultImage && (
        <div className="space-y-4 animate-in zoom-in-95 duration-500">
          <div className="flex items-center justify-between px-2">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Masterpiece Ready</h3>
            <div className="flex gap-2">
              <button 
                onClick={() => {
                  const link = document.createElement('a');
                  link.href = resultImage;
                  link.download = `bdm102-${Date.now()}.png`;
                  link.click();
                }}
                className="bg-slate-800 p-2 rounded-lg border border-slate-700 hover:bg-slate-700"
              >
                <Download className="w-4 h-4" />
              </button>
              <button 
                onClick={() => { setResultImage(null); setEditSource(null); }}
                className="bg-red-900/20 text-red-500 p-2 rounded-lg border border-red-500/20 hover:bg-red-900/30"
              >
                <Eraser className="w-4 h-4" />
              </button>
            </div>
          </div>
          <div className="bg-slate-900 p-2 border border-slate-800 rounded-3xl shadow-2xl overflow-hidden ring-1 ring-white/5">
            <img src={resultImage} className="w-full rounded-2xl" alt="AI Generated" />
          </div>
        </div>
      )}

      {/* Quick Suggestions */}
      {!resultImage && !isProcessing && (
        <div className="space-y-3">
          <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] px-2 flex items-center gap-2">
            <SlidersHorizontal className="w-3 h-3" />
            Quick Suggestions
          </h4>
          <div className="flex flex-wrap gap-2 px-1">
            {mode === 'generate' ? [
              "Vintage film style", "Sunset silhouette", "Cinematic drone shot", "Pencil sketch"
            ].map(suggestion => (
              <button key={suggestion} onClick={() => setPrompt(prev => prev + " " + suggestion)} className="bg-slate-900 border border-slate-800 text-xs px-3 py-1.5 rounded-full text-slate-400 hover:text-white hover:border-slate-700 transition-all">
                {suggestion}
              </button>
            )) : [
              "Enhance colors", "Add retro filter", "Make it black and white", "Remove background"
            ].map(suggestion => (
              <button key={suggestion} onClick={() => setPrompt(suggestion)} className="bg-slate-900 border border-slate-800 text-xs px-3 py-1.5 rounded-full text-slate-400 hover:text-white hover:border-slate-700 transition-all">
                {suggestion}
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default ImageStudio;

import React from 'react';
import { ShieldAlert, Key, ArrowRight, ExternalLink } from 'lucide-react';

interface ApiKeyGuardProps {
  onKeySelected: () => void;
}

const ApiKeyGuard: React.FC<ApiKeyGuardProps> = ({ onKeySelected }) => {
  const handleOpenSelector = async () => {
    // @ts-ignore
    if (window.aistudio) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
      onKeySelected();
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh] px-8 text-center animate-in fade-in zoom-in-95">
