import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI } from '@google/genai';
import { Play, Pause, RotateCcw, Zap, Brain, ChevronRight, Info } from 'lucide-react';

const RunWalkStrategy: React.FC = () => {
  const [runMinutes, setRunMinutes] = useState(4);
  const [walkMinutes, setWalkMinutes] = useState(1);
  const [isActive, setIsActive] = useState(false);
  const [mode, setMode] = useState<'RUN' | 'WALK'>('RUN');
  const [timeLeft, setTimeLeft] = useState(4 * 60);
  const [advisorLoading, setAdvisorLoading] = useState(false);
  const [advice, setAdvice] = useState<string | null>(null);

  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    if (isActive && timeLeft > 0) {
      timerRef.current = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      const nextMode = mode === 'RUN' ? 'WALK' : 'RUN';
      setMode(nextMode);
      setTimeLeft((nextMode === 'RUN' ? runMinutes : walkMinutes) * 60);
      // Play a subtle beep or vibration here if desired
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isActive, timeLeft, mode, runMinutes, walkMinutes]);

  const toggleTimer = () => setIsActive(!isActive);
  const resetTimer = () => {
    setIsActive(false);
    setMode('RUN');
    setTimeLeft(runMinutes * 60);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getAdvice = async () => {
    setAdvisorLoading(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `I am running the Bataan Death March 102km Ultramarathon. It is a flat but very hot road race. I am planning a run-walk strategy of ${runMinutes} minutes running and ${walkMinutes} minutes walking. Give me a 2-sentence tip on how to adjust this as I reach KM 70-80 when fatigue is highest.`,
        config: { temperature: 0.7 }
      });
      setAdvice(response.text || "Pace yourself and stay hydrated.");
    } catch (e) {
      setAdvice("Focus on maintaining effort rather than speed. Walk the hills, run the flats.");
    } finally {
      setAdvisorLoading(false);
    }
  };

  const totalCycle = (runMinutes + walkMinutes) * 60;
  const progress = (timeLeft / (mode === 'RUN' ? runMinutes * 60 : walkMinutes * 60)) * 100;

  return (
    <div className="p-4 space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Timer Display */}
      <div className={`relative overflow-hidden bg-slate-900 border-2 rounded-3xl p-8 text-center transition-colors duration-500 ${mode === 'RUN' ? 'border-red-500/30' : 'border-blue-500/30'}`}>
        <div className={`absolute top-0 left-0 h-1 transition-all duration-1000 ${mode === 'RUN' ? 'bg-red-500' : 'bg-blue-500'}`} style={{ width: `${100 - progress}%` }} />

        <span className={`text-xs font-bold uppercase tracking-[0.3em] ${mode === 'RUN' ? 'text-red-500' : 'text-blue-500'}`}>
          Current State: {mode}
        </span>

        <div className="my-4">
          <span className="text-7xl font-black tabular-nums tracking-tight text-white">
            {formatTime(timeLeft)}
          </span>
        </div>

        <div className="flex justify-center gap-4 mt-6">
          <button 
            onClick={toggleTimer}
            className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${isActive ? 'bg-slate-800 text-white' : 'bg-white text-slate-950 shadow-xl shadow-white/10'}`}
          >
            {isActive ? <Pause className="w-6 h-6" /> : <Play className="w-6 h-6 ml-1" />}
          </button>
          <button 
            onClick={resetTimer}
            className="w-14 h-14 rounded-full bg-slate-800 text-slate-400 flex items-center justify-center hover:text-white transition-colors"
          >
            <RotateCcw className="w-6 h-6" />
          </button>
        </div>
      </div>

      {/* Configuration Section */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-slate-900/50 border border-slate-800 rounded-2xl p-4">
          <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3">Run (Min)</label>
          <div className="flex items-center gap-4">
            <input 
              type="range" min="1" max="20" step="1" 
              value={runMinutes} 
              onChange={(e) => {
                const val = parseInt(e.target.value);
                setRunMinutes(val);
                if (!isActive) setTimeLeft(val * 60);
              }}
              className="w-full accent-red-500 h-1.5 bg-slate-800 rounded-lg appearance-none"
            />
            <span className="text-xl font-bold text-white min-w-[2ch]">{runMinutes}</span>
          </div>
        </div>
        <div className="bg-slate-900/50 border border-slate-800 rounded-2xl p-4">
          <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3">Walk (Min)</label>
          <div className="flex items-center gap-4">
            <input 
              type="range" min="1" max="10" step="1" 
              value={walkMinutes} 
              onChange={(e) => setWalkMinutes(parseInt(e.target.value))}
              className="w-full accent-blue-500 h-1.5 bg-slate-800 rounded-lg appearance-none"
            />
            <span className="text-xl font-bold text-white min-w-[2ch]">{walkMinutes}</span>
          </div>
        </div>
      </div>

      {/* Preset Strategies */}
      <div className="space-y-3">
        <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-1 flex items-center gap-2">
          <Zap className="w-3 h-3" />
          Pro Strategies
        </h4>
        <div className="grid grid-cols-3 gap-2">
          {[
            { label: '5:1 Power', r: 5, w: 1 },
            { label: '4:1 Standard', r: 4, w: 1 },
            { label: '2:1 Survival', r: 2, w: 1 },
          ].map(strat => (
            <button 
              key={strat.label}
              onClick={() => {
                setRunMinutes(strat.r);
                setWalkMinutes(strat.w);
                resetTimer();
              }}
              className="bg-slate-900 border border-slate-800 py-3 rounded-xl text-[11px] font-bold text-slate-400 hover:text-white hover:border-slate-600 transition-all text-center leading-tight px-2"
            >
              {strat.label}
              <div className="text-[9px] opacity-60 mt-1">{strat.r}m/{strat.w}m</div>
            </button>
          ))}
        </div>
      </div>

      {/* AI Strategy Advisor */}
      <div className="relative overflow-hidden group">
        <div className="absolute inset-0 bg-gradient-to-r from-blue-600 to-purple-600 opacity-10 rounded-3xl" />
        <div className="relative bg-slate-900/40 backdrop-blur-sm border border-white/10 rounded-3xl p-5">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className="bg-blue-500/20 p-2 rounded-xl">
                <Brain className="w-5 h-5 text-blue-400" />
              </div>
              <div>
                <h3 className="text-sm font-bold text-white leading-none">Strategy Advisor</h3>
                <p className="text-[10px] text-slate-400 mt-1">AI-powered pacing insights</p>
              </div>
            </div>
            {!advice && !advisorLoading && (
              <button 
                onClick={getAdvice}
                className="bg-white/10 hover:bg-white/20 p-2 rounded-full transition-colors"
              >
                <ChevronRight className="w-4 h-4 text-white" />
              </button>
            )}
          </div>

          {advisorLoading ? (
            <div className="flex items-center gap-3 p-2">
              <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce" />
              <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce delay-150" />
              <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce delay-300" />
              <span className="text-xs font-medium text-slate-500 italic">Calculating optimal effort...</span>
            </div>
          ) : advice ? (
            <div className="bg-slate-900/60 rounded-2xl p-4 border border-white/5 animate-in fade-in slide-in-from-top-2">
              <p className="text-xs text-slate-300 leading-relaxed italic">"{advice}"</p>
              <button 
                onClick={() => setAdvice(null)}
                className="mt-3 text-[10px] font-bold text-blue-400 uppercase tracking-widest hover:text-blue-300 transition-colors"
              >
                Refresh Advice
              </button>
            </div>
          ) : (
            <p className="text-xs text-slate-500 px-1">Get custom pacing advice for your BDM journey.</p>
          )}
        </div>
      </div>

      {/* Info Card */}
      <div className="flex gap-4 p-4 bg-slate-900 border border-slate-800 rounded-2xl">
        <Info className="w-5 h-5 text-slate-500 flex-shrink-0" />
        <p className="text-[11px] text-slate-500 leading-normal">
          Running an ultramarathon is as much about the walk as the run. A consistent interval strategy helps manage core temperature and muscle fatigue in the Bataan heat.
        </p>
      </div>
    </div>
  );
};

